if (point.gradient) {
  const defs = document.createElementNS(SVG_NAMESPACE_URI, 'defs');
  gEle.node()!.appendChild(defs);

  const linearGradient = document.createElementNS(SVG_NAMESPACE_URI, 'linearGradient');
  defs.appendChild(linearGradient);
  gradientId = `gradient-${barNo}-${index}`;
  linearGradient.setAttribute('id', gradientId);

  const stop1 = document.createElementNS(SVG_NAMESPACE_URI, 'stop');
  linearGradient.appendChild(stop1);
  stop1.setAttribute('offset', '0%');
  stop1.setAttribute('stop-color', point.gradient[0]);

  const stop2 = document.createElementNS(SVG_NAMESPACE_URI, 'stop');
  linearGradient.appendChild(stop2);
  stop2.setAttribute('offset', '100%');
  stop2.setAttribute('stop-color', point.gradient[1]);
}

if (isArrayOrTypedArray(colors)) {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (colors as any[]).forEach((element, index) => {
    const colorString = element?.toString().trim();
    const nextFluentColor = getColor(`Label_${index}`, colorMap, templateColorway, isDarkTheme, isDonut);
    if (colorString) {
      const parsedColor = d3Color(colorString);
      hexColors.push(
        parsedColor ? tryMapFluentDataViz(parsedColor.formatHex(), templateColorway, isDarkTheme) : nextFluentColor,
      );
    } else {
      hexColors.push(nextFluentColor);
    }
  });
} else if (typeof colors === 'string') {
  const parsedColor = d3Color(colors);
  return parsedColor
    ? tryMapFluentDataViz(parsedColor.formatHex(), templateColorway, isDarkTheme)
    : getColor('Label_0', colorMap, templateColorway, isDarkTheme, isDonut);
}

if (centerLegends) {
  legendLines.forEach((ln, idx) => {
    const lineOffsetX = Math.max((svgWidth - legendLineWidths[idx]) / 2, 0);
    let remLineWidth = legendLineWidths[idx];
    let itemOffsetX = 0;
    ln.forEach(item => {
      const newOffsetX = lineOffsetX + (isRTL ? remLineWidth - item.width - itemOffsetX : 0);
      item.elem.attr('transform', `translate(${newOffsetX}, 0)`);
      remLineWidth -= item.width;
      itemOffsetX += item.width;
    });
  });
} else if (isRTL) {
  const w1 = Math.max(svgWidth, ...legendLineWidths);
  legendLines.forEach(ln => {
    let remLineWidth = w1 - LEGEND_CONTAINER_MARGIN_START;
    let itemOffsetX = LEGEND_CONTAINER_MARGIN_START;
    ln.forEach(item => {
      const newOffsetX = remLineWidth - item.width - itemOffsetX;
      item.elem.attr('transform', `translate(${newOffsetX}, 0)`);
      remLineWidth -= item.width;
      itemOffsetX += item.width;
    });
  });
}

if ([ChartTypes.AreaChart, ChartTypes.LineChart, ChartTypes.ScatterChart].includes(chartType)) {
  [sDate, lDate] = getScatterXDomainExtent(points as ILineChartPoints[]) as [Date, Date];
  // Need to draw graph with given small and large date
  // (Which Involves customization of date axis tick values)
  // That may be Either from given graph data or from prop 'tickValues' date values.
  // So, Finding smallest and largest dates
  sDate = d3Min([...tickValues, sDate])!;
  lDate = d3Max([...tickValues, lDate])!;

  if (hasMarkersMode || chartType === ChartTypes.ScatterChart) {
    const xPadding = getDomainPaddingForMarkers(sDate.getTime(), lDate.getTime());
    sDate = new Date(sDate.getTime() - xPadding.start);
    lDate = new Date(lDate.getTime() + xPadding.end);
  }
} else {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  sDate = d3Min(points as any[], point => point.x as Date)!;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  lDate = d3Max(points as any[], point => point.x as Date)!;
}

if ([ChartTypes.AreaChart, ChartTypes.LineChart, ChartTypes.ScatterChart].includes(chartType)) {
  [sDate, lDate] = getScatterXDomainExtent(points as LineChartPoints[]) as [Date, Date];
  // Need to draw graph with given small and large date
  // (Which Involves customization of date axis tick values)
  // That may be Either from given graph data or from prop 'tickValues' date values.
  // So, Finding smallest and largest dates
  sDate = d3Min([...tickValues, sDate])!;
  lDate = d3Max([...tickValues, lDate])!;

  if (hasMarkersMode || chartType === ChartTypes.ScatterChart) {
    const xPadding = getDomainPaddingForMarkers(sDate.getTime(), lDate.getTime());
    sDate = new Date(sDate.getTime() - xPadding.start);
    lDate = new Date(lDate.getTime() + xPadding.end);
  }
} else {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  sDate = d3Min(points as any[], point => point.x as Date)!;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  lDate = d3Max(points as any[], point => point.x as Date)!;
}

if (state.icon) {
  let iconSizeClass;
  if (size <= 16) {
    iconSizeClass = styles.icon12;
  } else if (size <= 24) {
    iconSizeClass = styles.icon16;
  } else if (size <= 40) {
    iconSizeClass = styles.icon20;
  } else if (size <= 48) {
    iconSizeClass = styles.icon24;
  } else if (size <= 56) {
    iconSizeClass = styles.icon28;
  } else if (size <= 72) {
    iconSizeClass = styles.icon32;
  } else {
    iconSizeClass = styles.icon48;
  }

  // eslint-disable-next-line react-hooks/immutability
  state.icon.className = mergeClasses(
    avatarClassNames.icon,
    iconInitialsClassName,
    iconSizeClass,
    colorStyles[color],
    state.badge && styles.badgeCutout,
    state.icon.className,
  );
}

if (imageFileType === 'svg' && devicePixelRatio > 1 && devicePixelRatio <= 1.5) {
  // Currently missing 1.5x SVGs at size 20, snap to 1x for now
  if (size !== 20) {
    devicePixelRatioSuffix = '_1.5x';
  }
} else if (imageFileType === 'png') {
  // To look good, PNGs should use a different image for higher device pixel ratios
  if (devicePixelRatio > 1 && devicePixelRatio <= 1.5) {
    // Currently missing 1.5x icons for size 20, snap to 2x for now
    devicePixelRatioSuffix = size === 20 ? '_2x' : '_1.5x';
  } else if (devicePixelRatio > 1.5 && devicePixelRatio <= 2) {
    devicePixelRatioSuffix = '_2x';
  } else if (devicePixelRatio > 2 && devicePixelRatio <= 3) {
    devicePixelRatioSuffix = '_3x';
  } else if (devicePixelRatio > 3) {
    devicePixelRatioSuffix = '_4x';
  }
}

if (preset === Preset.ReactStandalone || preset === Preset.ReactMonorepo) {
  bundler = useReactRouter ? 'vite' : await determineReactBundler(parsedArgs);
  unitTestRunner = await determineUnitTestRunner(parsedArgs, {
    preferVitest: bundler === 'vite',
  });
  e2eTestRunner = await determineE2eTestRunner(parsedArgs);
} else if (preset === Preset.NextJs || preset === Preset.NextJsStandalone) {
  nextAppDir = await determineNextAppDir(parsedArgs);
  nextSrcDir = await determineNextSrcDir(parsedArgs);
  unitTestRunner = await determineUnitTestRunner(parsedArgs, {
    exclude: 'vitest',
  });
  e2eTestRunner = await determineE2eTestRunner(parsedArgs);
} else if (preset === Preset.ReactNative || preset === Preset.Expo) {
  unitTestRunner = await determineUnitTestRunner(parsedArgs, {
    exclude: 'vitest',
  });
  e2eTestRunner = await determineE2eTestRunner(parsedArgs);
}

if (force === 'v8' || isV8SerializerEnabled()) {
  try {
    return v8_serialize(data).toString('binary');
  } catch (e) {
    if (force !== 'v8') {
      console.warn(
        `Data could not be serialized using v8 serialization: ${e}. Falling back to JSON serialization.`
      );
      // Fall back to JSON serialization
      return JSON.stringify(data);
    }
    throw e;
  }
} else {
  try {
    return JSON.stringify(data);
  } catch (e) {
    if (force !== 'json') {
      // Fall back to v8 serialization
      console.warn(
        `Data could not be serialized using JSON.stringify: ${e}. Falling back to v8 serialization.`
      );
      return v8_serialize(data).toString('binary');
    }
    throw e;
  }
}

switch (process.platform) {
  case 'darwin':
    return 'ioreg -rd1 -c IOPlatformExpertDevice';
  case 'win32': {
    const regPath =
      process.arch === 'ia32' &&
      process.env.hasOwnProperty('PROCESSOR_ARCHITEW6432')
        ? '%windir%\\sysnative\\cmd.exe /c %windir%\\System32'
        : '%windir%\\System32';
    return (
      `${regPath}\\REG.exe ` +
      'QUERY HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Cryptography ' +
      '/v MachineGuid'
    );
  }
  case 'linux':
    return '( cat /var/lib/dbus/machine-id /etc/machine-id 2> /dev/null || hostname ) | head -n 1 || :';
  case 'freebsd':
    return 'kenv -q smbios.system.uuid || sysctl -n kern.hostuuid';
  default:
    throw new Error(`Unsupported platform: ${process.platform}`);
}

try {
  const yarnLockFile = await gfs.readFile(path.join(dir, 'yarn.lock'), 'utf8')
  const yarnLockFileType = getYarnLockfileType(yarnLockFile)
  if (yarnLockFileType === YarnLockType.yarn) {
    const lockJsonFile = parseYarnLockfile(yarnLockFile)
    if (lockJsonFile.type === 'success') {
      return lockJsonFile.object
    } else {
      throw new PnpmError('YARN_LOCKFILE_PARSE_FAILED', `Yarn.lock file was ${lockJsonFile.type}`)
    }
  } else if (yarnLockFileType === YarnLockType.yarn2) {
    const lockJsonFile = parseYarn2Lock(yarnLockFile)
    if (lockJsonFile.type === YarnLockType.yarn2) {
      return lockJsonFile.object
    }
  }
} catch (err: any) { // eslint-disable-line
  if (err['code'] !== 'ENOENT') throw err
}

for (const depPaths of duplicates) {
  const unresolvedDepPaths = new Set(depPaths.values())
  let currentDepPaths = [...depPaths].sort(depCountSorter)

  while (currentDepPaths.length) {
    const depPath1 = currentDepPaths.pop()!
    const nextDepPaths = []
    while (currentDepPaths.length) {
      const depPath2 = currentDepPaths.pop()!
      if (isCompatibleAndHasMoreDeps(depGraph, depPath1, depPath2)) {
        depPathsMap[depPath2] = depPath1
        unresolvedDepPaths.delete(depPath1)
        unresolvedDepPaths.delete(depPath2)
      } else {
        nextDepPaths.push(depPath2)
      }
    }
    nextDepPaths.push(...currentDepPaths)
    currentDepPaths = nextDepPaths.sort(depCountSorter)
  }

  if (unresolvedDepPaths.size) {
    remainingDuplicates.push(unresolvedDepPaths)
  }
}

if (uri.indexOf(':') < 0 && !uri.startsWith('/')) {
  if (wsFolders.length === 1) {
    const wsUri = URI.parse(wsFolders[0].uri);
    uri = wsUri.with({ path: wsUri.path + uri }).toString();
  }
} else if (uri.startsWith('file://') && wsFolders.length === 1 && URI.parse(wsFolders[0].uri).scheme != 'file') {
  const wsUri = URI.parse(wsFolders[0].uri);
  const pathFromUri = URI.parse(uri).path;
  uri = wsUri.with({ path: pathFromUri }).toString();
} else if (!uri.startsWith('file') && !uri.startsWith('/') && !/^[a-z]:[\\/]/i.test(uri)) {
  // if uri points to local file of its a windows path
  const origUri = URI.parse(uri);
  const customUri = URI.from({
    scheme: 'json-schema',
    authority: origUri.authority,
    path: origUri.path.endsWith('.json') ? origUri.path : origUri.path + '.json',
    fragment: uri,
  });
  uri = customUri.toString();
}

for (let exportName of staticExports) {
  if (isClientRouteExport(exportName)) {
    result += `export { ${exportName} } from "${createId(
      id,
      "client-route-module",
      routeChunks.hasRouteChunkByExportName[
        exportName as RouteChunkExportName
      ]
        ? exportName
        : "shared",
    )}";\n`;
  } else if (isServerComponentExport(exportName)) {
    needsReactImport = true;
    result += `import { ${exportName} as ${exportName}WithoutCss } from "${createId(id, "server-route-module")}";\n`;
    result += `export function ${exportName}(props) {\n`;
    result += `  return React.createElement(React.Fragment, null,\n`;
    result += `    import.meta.viteRsc.loadCss(),\n`;
    result += `    React.createElement(EnsureClientRouteModuleForHMR___, null),\n`;
    result += `    React.createElement(${exportName}WithoutCss, props),\n`;
    result += `  );\n`;
    result += `}\n`;
  } else {
    result += `export { ${exportName} } from "${createId(id, "server-route-module")}";\n`;
  }
}

switch (valueType) {
  case 'esNode':
    return String(value.type);
  case 'scope':
    return `${ucFirst(String(value.type))}Scope$${String(value.$id)}`;
  case 'scopeDefinition':
    return `Definition#${String(value.type)}$${String(value.$id)}`;
  case 'scopeManager':
    return 'ScopeManager';
  case 'scopeReference':
    return `Reference#${String(
      isRecord(value.identifier) ? value.identifier.name : 'unknown',
    )}$${String(value.$id)}`;
  case 'scopeVariable':
    return `Variable#${String(value.name)}$${String(value.$id)}`;
  case 'tsNode':
    return tsEnumToString('SyntaxKind', Number(value.kind));
  case 'tsSignature':
    return '[Signature]';
  case 'tsSymbol':
    return `Symbol(${String(value.escapedName)})`;
  case 'tsType':
    return '[Type]';
}

for (let i = 0; i < len; i += 3) {
  if (len === i + 1) { // last 1 byte
    const a = (bytes[i] & 0xFC) >> 2
    const b = ((bytes[i] & 0x03) << 4)
    base64 += table[a]
    base64 += table[b]
    base64 += '=='
  }
  else if (len === i + 2) { // last 2 bytes
    const a = (bytes[i] & 0xFC) >> 2
    const b = ((bytes[i] & 0x03) << 4) | ((bytes[i + 1] & 0xF0) >> 4)
    const c = ((bytes[i + 1] & 0x0F) << 2)
    base64 += table[a]
    base64 += table[b]
    base64 += table[c]
    base64 += '='
  }
  else {
    const a = (bytes[i] & 0xFC) >> 2
    const b = ((bytes[i] & 0x03) << 4) | ((bytes[i + 1] & 0xF0) >> 4)
    const c = ((bytes[i + 1] & 0x0F) << 2) | ((bytes[i + 2] & 0xC0) >> 6)
    const d = bytes[i + 2] & 0x3F
    base64 += table[a]
    base64 += table[b]
    base64 += table[c]
    base64 += table[d]
  }
}

for (let i = styles.length - 1; i >= 0; i--) {
  const s = document.createElement('style')
  if (nonce) s.setAttribute('nonce', nonce)
  s.textContent = styles[i]

  root.insertBefore(s, last || insertionAnchor)
  last = s
  if (i === 0) {
    if (!parentComp) this._styleAnchors.set(this._def, s)
    if (owner) this._styleAnchors.set(owner, s)
  }

  // record for HMR
  if (__DEV__) {
    if (owner) {
      if (owner.__hmrId) {
        if (!this._childStyles) this._childStyles = new Map()
        let entry = this._childStyles.get(owner.__hmrId)
        if (!entry) {
          this._childStyles.set(owner.__hmrId, (entry = []))
        }
        entry.push(s)
      }
    } else {
      ;(this._styles || (this._styles = [])).push(s)
    }
  }
}

if (ctx.dollarVars.size) {
	yield `var ${names.dollars}!: {${newLine}`;
	if (ctx.dollarVars.has('$slots')) {
		const type = ctx.generatedTypes.has(names.Slots) ? names.Slots : `{}`;
		yield `$slots: ${type}${endOfLine}`;
	}
	if (ctx.dollarVars.has('$attrs')) {
		yield `$attrs: import('${vueCompilerOptions.lib}').ComponentPublicInstance['$attrs']`;
		if (ctx.generatedTypes.has(names.InheritedAttrs)) {
			yield ` & ${names.InheritedAttrs}`;
		}
		yield endOfLine;
	}
	if (ctx.dollarVars.has('$refs')) {
		const type = ctx.generatedTypes.has(names.TemplateRefs) ? names.TemplateRefs : `{}`;
		yield `$refs: ${type}${endOfLine}`;
	}
	if (ctx.dollarVars.has('$el')) {
		const type = ctx.generatedTypes.has(names.RootEl) ? names.RootEl : `any`;
		yield `$el: ${type}${endOfLine}`;
	}
	yield `} & { [K in keyof import('${vueCompilerOptions.lib}').ComponentPublicInstance]: unknown }${endOfLine}`;
}

if (fs.existsSync(filePath)) {
  const varFile = fs.readFileSync(filePath, 'utf8')
  const vars = varFile.replace(/\/\/.+[\r\n]+/g, '').split(/;[\n]*/g)
  const varValues: Record<string, { default: string, use?: string }> = {}
  for (const [index, variable] of vars.entries()) {
    const varArr = variable.split(':')
    if (varArr.length >= 2 && varArr[0].startsWith('$')) {
      const varName = varArr.shift()!.trim()
      const varDefault = (vars[index + 1].startsWith('@'))
        ? vars[index + 1]
        : varArr.join(':')
      varValues[varName] = {
        default: varDefault.replace('!default', '').trim(),
        ...{ use: tagUse === 'all' || tagUse?.includes(varName) ? 'vuetify' : 'vuetify/settings' },
      }
    }
  }
  return varValues
}
